namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainerService> _logger;

    public ModelTrainerService(ILogger<ModelTrainerService> logger)
    {
        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public void TrainAndSave()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns and combine with Priority
        var pipeline = mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model with {TrainRows} training rows...",
            split.TrainSet.GetRowCount());

        ITransformer model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        IDataView predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation(
            "Model evaluation — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

        LogConfusionMatrix(metrics);

        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }

    private void LogConfusionMatrix(
        Microsoft.ML.Data.MulticlassClassificationMetrics metrics)
    {
        var cm = metrics.ConfusionMatrix;
        _logger.LogInformation("Confusion matrix (per-class):");

        for (int i = 0; i < cm.PerClassPrecision.Count; i++)
        {
            _logger.LogInformation(
                "  Class {Index}: Precision={Precision:F4}, Recall={Recall:F4}",
                i, cm.PerClassPrecision[i], cm.PerClassRecall[i]);
        }
    }

    public string GetModelPath() => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] TicketRequest request)
    {
        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        return Ok(new ClassifyResponse
        {
            Category = prediction.Category,
            Confidence = prediction.Score.Max()
        });
    }
}

public class ClassifyResponse
{
    public required string Category { get; set; }
    public float Confidence { get; set; }
}

